dslRuleAfterChange:
// Hypothetical DSL extensions for type inference:

// Rule 1: Add generics to Map variable declaration assigned from a known API
// This would require a guard that checks the return type of the method call.
java.util.Map $var = org.eclipse.jdt.core.JavaCore.getOptions($args$) :: 
  inferredGenericTypeMatch($var, "java.lang.String", "java.lang.String")
=> java.util.Map<java.lang.String, java.lang.String> $var = org.eclipse.jdt.core.JavaCore.getOptions($args$)
;;

// Rule 2: Add generics to Map variable declaration from IJavaProject instance method
java.util.Map $var = $project.getOptions($args$) :: 
  instanceof($project, "org.eclipse.jdt.core.IJavaProject") && inferredGenericTypeMatch($var, "java.lang.String", "java.lang.String")
=> java.util.Map<java.lang.String, java.lang.String> $var = $project.getOptions($args$)
;;

// Rule 3: Add generics to Map method parameter in a specific class
// This requires checking the type of the parameter and restricting the class context.
void $name(java.util.Map $param$) :: 
  inClass("org.eclipse.jdt.core.dom.ASTParser") && inferredGenericTypeMatch($param, "java.lang.String", "java.lang.String")
=> void $name(java.util.Map<java.lang.String, java.lang.String> $param$)
;;

// Rule 4: Apply diamond operator, this is already implementable (see summary)
new java.util.HashMap($options)
=> new java.util.HashMap<>($options)
;;

